mapper.insert:
/** CmmtPopupDao.insert */
insert into cmmt_popup (
	 popup_id
	,system_id
	,popup_type
	,title
	,article
	,posting
	,begin_dt
	,end_dt
	,popup_width
	,popup_height
	,image_file_id
	,image_alt_cn
	,link_url
	,new_window
	,creator_id
	,created_dt
	,updater_id
	,updated_dt
) values (
	 #{popupId}
	,#{systemId}
	,#{popupType}
	,#{title}
	,#{article}
	,#{posting}
	,#{beginDt}
	,#{endDt}
	,#{popupWidth}
	,#{popupHeight}
	,#{imageFileId}
	,#{imageAltCn}
	,#{linkUrl}
	,#{newWindow}
	,#{creatorId}
	,#{createdDt}
	,#{updaterId}
	,#{updatedDt}
)

mapper.select:
/** CmmtPopupDao.select */
SELECT

FROM
	cmmt_popup
WHERE
	POPUP_ID = #{popupId}

mapper.update:
/** CmmtPopupDao.update */
update cmmt_popup set
	 system_id	   = #{systemId}
	,popup_type    = #{popupType}
	,title         = #{title}
	,article       = #{article}
	,posting	   = #{posting}
	,begin_dt      = #{beginDt}
	,end_dt        = #{endDt}
	,popup_width   = #{popupWidth}
	,popup_height  = #{popupHeight}
	,image_file_id = #{imageFileId}
	,image_alt_cn  = #{imageAltCn}
	,link_url      = #{linkUrl}
	,new_window	   = #{newWindow}
	,creator_id    = #{creatorId}
	,created_dt    = #{createdDt}
	,updater_id    = #{updaterId}
	,updated_dt    = #{updatedDt}
WHERE
	popup_id = #{popupId}

